reGate,\n133: \tpluginInitializers ...admission.PluginInitializer,\n134: ) error {\n135: \tif a == nil {\n136: \t\treturn nil\n137: \t}\n138: \n139: \t// Admission depends on CoreAPI to set SharedInformerFactory and ClientConfig.\n140: \tif informers == nil {\n141: \t\treturn fmt.Errorf(\"admission depends on a Kubernetes core API shared informer, it cannot be nil\")\n142: \t}\n143: \tif kubeClient == nil || dynamicClient == nil {\n144: \t\treturn fmt.Errorf(\"admission depends on a Kubernetes core API client, it cannot be nil\")\n145: \t}\n146: \n147: \tpluginNames := a.enabledPluginNames()\n148: \n149: \tpluginsConfigProvider, err := admission.ReadAdmissionConfiguration(pluginNames, a.ConfigFile, configScheme)\n150: \tif err != nil {\n151: \t\treturn fmt.Errorf(\"failed to read plugin config: %v\", err)\n152: \t}\n153: \n154: \tdiscoveryClient := cacheddiscovery.NewMemCacheClient(kubeClient.Discovery())\n155: \tdiscoveryRESTMapper := restmapper.NewDeferredDiscoveryRESTMapper(discoveryClient)\n156: \tgenericInitializer := initializer.New(kubeClient, dynamicClient, informers, c.Authorization.Authorizer, features,\n157: \t\tc.DrainedNotify(), discoveryRESTMapper)\n158: \tinitializersChain := admission.PluginInitializers{genericInitializer}\n159: \tinitializersChain = append(initializersChain, pluginInitializers...)\n160: \n161: \tadmissionPostStartHook := func(hookContext server.PostStartHookContext) error {\n162: \t\tdiscoveryRESTMapper.Reset()\n163: \t\tgo utilwait.Until(discoveryRESTMapper.Reset, 30*time.Second, hookContext.Done())\n164: \t\treturn nil\n165: \t}\n166: \n167: \terr = c.AddPostStartHook(\"start-apiserver-admission-initializer\", admissionPostStartHook)\n168: \tif err != nil {\n169: \t\treturn fmt.Errorf(\"failed to add post start hook for policy admission: %w\", err)\n170: \t}\n171: \n172: \tadmissionChain, err := a.Plugins.NewFromPlugins(pluginNames, pluginsConfigProvider, initializersChain, a.Decorators)\n173: \tif err != nil {\n174: \t\treturn err\n175: \t}\n176: \n177: \tc.AdmissionControl = admissionmetrics.WithStepMetrics(admissionChain)\n178: \treturn nil\n179: }\n180: \n181: // Validate verifies flags passed to AdmissionOptions.\n182: func (a *AdmissionOptions) Validate() []error {\n183: \tif a == nil {\n184: \t\treturn nil\n185: \t}\n186: \n187: \terrs := []error{}\n188: \n189: \tregisteredPlugins := sets.NewString(a.Plugins.Registered()...)\n190: \tfor _, name := range a.EnablePlugins {\n191: \t\tif !registeredPlugins.Has(name) {\n192: \t\t\terrs = append(errs, fmt.Errorf(\"enable-admission-plugins plugin %q is unknown\", name))\n193: \t\t}\n194: \t}\n195: \n196: \tfor _, name := range a.DisablePlugins {\n197: \t\tif !registeredPlugins.Has(name) {\n198: \t\t\terrs = append(errs, fmt.Errorf(\"disable-admission-plugins plugin %q is unknown\", name))\n199: \t\t}\n200: \t}\n201: \n202: \tenablePlugins := sets.NewString(a.EnablePlugins...)\n203: \tdisablePlugins := sets.NewString(a.DisablePlugins...)\n204: \tif len(enablePlugins.Intersection(disablePlugins).List()) \u003e 0 {\n205: \t\terrs = append(errs, fmt.Errorf(\"%v in enable-admission-plugins and disable-admission-plugins \"+\n206: \t\t\t\"overlapped\", enablePlugins.Intersection(disablePlugins).List()))\n207: \t}\n208: \n209: \t// Verify RecommendedPluginOrder.\n210: \trecommendPlugins := sets.NewString(a.RecommendedPluginOrder...)\n211: \tintersections := registeredPlugins.Intersection(recommendPlugins)\n212: \tif !intersections.Equal(recommendPlugins) {\n213: \t\t// Developer error, this should never run in.\n214: \t\terrs = append(errs, fmt.Errorf(\"plugins %v in RecommendedPluginOrder are not registered\",\n215: \t\t\trecommendPlugins.Difference(intersections).List()))\n216: \t}\n217: \tif !intersections.Equal(registeredPlugins) {\n218: \t\t// Developer error, this should never run in.\n219: \t\terrs = append(errs, fmt.Errorf(\"plugins %v registered are not in RecommendedPluginOrder\",\n220: \t\t\tregisteredPlugins.Difference(intersections).List()))\n221: \t}\n222: \n223: \treturn errs\n224: }\n225: \n226: // enabledPluginNames makes use of RecommendedPluginOrder, DefaultOffPlugins,\n227: // EnablePlugins, DisablePlugins fields\n228: // to prepare a list of ordered plugin names that are enabled.\n229: func (a *AdmissionOptions) enabledPluginNames() []string {\n230: \tallOffPlugins := append(sets.List[string](a.DefaultOffPlugins), a.DisablePlugins...)\n231: \tdisabledPlugins := sets.NewString(allOffPlugins...)\n232: \tenabledPlugins := sets.NewString(a.EnablePlugins...)\n233: \tdisabledPlugins = disabledPlugins.Difference(enabledPlugins)\n234: \n235: \torderedPlugins := []string{}\n236: \tfor _, plugin := range a.RecommendedPluginOrder {\n237: \t\tif !disabledPlugins.Has(plugin) {\n238: \t\t\torderedPlugins = append(orderedPlugins, plugin)\n239: \t\t}\n240: \t}\n241: \n242: \treturn orderedPlugins\n243: }\n244: \n245: // Return names of plugins which are enabled by default\n246: func (a *AdmissionOptions) defaultEnabledPluginNames() []string {\n247: \tdefaultOnPluginNames := []string{}\n248: \tfor _, pluginName := range a.RecommendedPluginOrder {\n249: \t\tif !a.DefaultOffPlugins.Has(pluginName) {\n250: \t\t\tdefaultOnPluginNames = append(defaultOnPluginNames, pluginName)\n251: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/kubernetes--v1.32.0@d17b464c6fcd3273e4b1f695890bf0af7d5b272d/-/blob/staging/src/k8s.io/apiserver/pkg/server/options/admission.go%3FL100-250"}", "annotations": null, "meta": null}], "structuredContent": {"content": "100: 
